            if not self.check_collision(self.current_piece, direction, 0):
                self.current_piece.x += direction

    def move_piece_down(self):
        if self.current_piece:
            if not self.check_collision(self.current_piece, 0, 1):
                self.current_piece.y += 1
                return True
            else:
                self.lock_piece()
                return False
        return False

    def rotate_piece(self):
        if self.current_piece:
            original_shape = [list(row) for row in self.current_piece.shape]
            self.current_piece.rotate()
            if self.check_collision(self.current_piece, 0, 0):
