        lines_cleared = self.clear_lines()
        matches_cleared = self.clear_matches()

        if lines_cleared > 0 or matches_cleared:
            self.handle_gravity()
            chain_cleared = True
            while chain_cleared:
                chain_cleared = self.clear_matches()
                if chain_cleared:
                    self.handle_gravity()
        self.spawn_new_piece()

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.grid_height):
